    $sections = @(
        @{ Title = 'Expired'; Items = $Report.Expired }
        @{ Title = 'Warning'; Items = $Report.Warning }
        @{ Title = 'Ok';      Items = $Report.Ok      }
    )
    foreach ($section in $sections) {
