        ,$report.Expired | Should -BeOfType [System.Array]
        ,$report.Warning | Should -BeOfType [System.Array]
        $report.Expired.Count | Should -Be 0
        $report.Warning.Count | Should -Be 0
        $report.Ok.Count      | Should -Be 1
    }
}

